#!/usr/bin/env python3
"""
Anti-Go-Horse Protocol (AGPH) Hook

Detects AI agent loop patterns and forces intelligent stops.

Triggers:
- Same error 2+ times → SEARCH
- Same file edited 3+ times → REVIEW
- Build/test failing 3+ times → ESCALATE

Run as PostToolUse hook.
"""

import json
import sys
import os
from pathlib import Path
from datetime import datetime

# State file location
SCRIPT_DIR = Path(__file__).parent
STATE_FILE = SCRIPT_DIR / "agph-state.json"
LOG_FILE = SCRIPT_DIR / "agph-log.json"


def load_state():
    """Load persistent state from file."""
    if STATE_FILE.exists():
        try:
            return json.loads(STATE_FILE.read_text())
        except json.JSONDecodeError:
            pass
    return {
        "errors": [],
        "edits": {},
        "failures": 0,
        "session_start": datetime.now().isoformat()
    }


def save_state(state):
    """Save state to file."""
    STATE_FILE.write_text(json.dumps(state, indent=2))


def log_intervention(intervention_type, details):
    """Log AGPH intervention for metrics."""
    log = []
    if LOG_FILE.exists():
        try:
            log = json.loads(LOG_FILE.read_text())
        except json.JSONDecodeError:
            pass

    log.append({
        "timestamp": datetime.now().isoformat(),
        "type": intervention_type,
        "details": details
    })

    # Keep last 100 entries
    log = log[-100:]
    LOG_FILE.write_text(json.dumps(log, indent=2))


def normalize_error(error_text):
    """Normalize error text for comparison."""
    if not error_text:
        return None
    # Take first 150 chars, remove line numbers and paths
    normalized = error_text[:150].lower()
    # Remove common variable parts
    import re
    normalized = re.sub(r'line \d+', 'line N', normalized)
    normalized = re.sub(r'column \d+', 'column N', normalized)
    normalized = re.sub(r'/[^\s]+/', '/PATH/', normalized)
    return normalized


def detect_loop(state, hook_data):
    """
    Detect loop patterns in agent behavior.

    Returns: (loop_type, details) or (None, None)
    """
    tool_name = hook_data.get("tool_name", "")
    tool_input = hook_data.get("tool_input", {})
    tool_output = hook_data.get("tool_output", "")

    # Check for error in output
    output_lower = str(tool_output).lower()
    has_error = any(word in output_lower for word in ["error", "failed", "exception", "traceback"])

    if has_error:
        error_sig = normalize_error(tool_output)
        if error_sig:
            count = state["errors"].count(error_sig)
            if count >= 1:  # Already seen once = 2 times total
                return "error_loop", {
                    "error": error_sig[:100],
                    "count": count + 1
                }
            state["errors"].append(error_sig)

    # Check for edit loop (same file edited multiple times)
    if tool_name in ["Edit", "Write"]:
        file_path = ""
        if isinstance(tool_input, dict):
            file_path = tool_input.get("file_path", tool_input.get("path", ""))
        elif isinstance(tool_input, str):
            # Try to extract path from string
            if "file_path" in tool_input:
                try:
                    parsed = json.loads(tool_input)
                    file_path = parsed.get("file_path", "")
                except:
                    pass

        if file_path:
            state["edits"][file_path] = state["edits"].get(file_path, 0) + 1
            if state["edits"][file_path] >= 3:
                return "edit_loop", {
                    "file": file_path,
                    "count": state["edits"][file_path]
                }

    # Check for build/test failure loop
    if tool_name == "Bash":
        command = ""
        if isinstance(tool_input, dict):
            command = tool_input.get("command", "")
        elif isinstance(tool_input, str):
            command = tool_input

        is_build_command = any(cmd in command.lower() for cmd in [
            "build", "test", "typecheck", "tsc", "npm run", "bun run", "pnpm"
        ])

        if is_build_command:
            if has_error or "FAIL" in str(tool_output):
                state["failures"] += 1
                if state["failures"] >= 3:
                    return "failure_loop", {
                        "command": command[:50],
                        "count": state["failures"]
                    }
            else:
                # Reset on success
                state["failures"] = 0

    return None, None


def get_remedy(loop_type, details):
    """Get remediation instructions for detected loop."""

    if loop_type == "error_loop":
        return {
            "level": 2,
            "action": "SEARCH",
            "message": f"""
🔴 AGPH ALERT: Same error detected {details['count']} times!

STOP trying variations. You are in a loop.

Required action:
1. WebSearch: "{details['error'][:50]}... solution 2025"
2. Read the search results carefully
3. Understand the ROOT CAUSE
4. Only then try a fix

Do NOT proceed without searching first.
"""
        }

    elif loop_type == "edit_loop":
        return {
            "level": 1,
            "action": "REVIEW",
            "message": f"""
🟡 AGPH ALERT: File edited {details['count']} times!

File: {details['file']}

STOP editing. You may be missing context.

Required action:
1. Read the ENTIRE file (not just the part you're editing)
2. Understand the surrounding code
3. Check if there's a different approach
4. Plan your edit BEFORE making it

Tip: Maybe the problem is elsewhere in the codebase.
"""
        }

    elif loop_type == "failure_loop":
        return {
            "level": 3,
            "action": "ESCALATE",
            "message": f"""
🟠 AGPH ALERT: Build/test failed {details['count']} times!

Command: {details['command']}

STOP running the same command. Time to escalate.

Required action (choose one):
1. WebSearch the specific error message
2. Read official documentation for the tool
3. Check if dependencies are installed correctly
4. Ask: Is there a simpler approach?

If nothing works after research, document the blocker
and ask the human for help.
"""
        }

    return None


def main():
    """Main hook logic."""
    # Read hook data from stdin
    try:
        hook_data = json.loads(sys.stdin.read())
    except json.JSONDecodeError:
        # No valid JSON input, skip
        return

    state = load_state()

    loop_type, details = detect_loop(state, hook_data)

    if loop_type:
        remedy = get_remedy(loop_type, details)
        if remedy:
            print(remedy["message"])
            log_intervention(loop_type, {
                "details": details,
                "remedy_level": remedy["level"]
            })
            # Reset relevant state after intervention
            if loop_type == "error_loop":
                state["errors"] = []
            elif loop_type == "edit_loop":
                state["edits"] = {}
            elif loop_type == "failure_loop":
                state["failures"] = 0

    save_state(state)


if __name__ == "__main__":
    main()

